class Solution {
public:
    bool uniqueOccurrences(vector<int>& arr) {
        unordered_map<int, int> count;
        for (int num : arr) {
            count[num]++;
        }
        unordered_map<int, bool> occurrence;
        for (auto& pair : count) {
            if (occurrence.find(pair.second) != occurrence.end()) {
                return false;
            }
            occurrence[pair.second] = true;
        }
        return true;
    }
};
